class Solution:
    def maxStudents(self, seats):
        m = len(seats)
        n = len(seats[0])
        good = []
        for row in seats:
            g = 0
            for j, ch in enumerate(row):
                if ch == '.':
                    g |= 1 << j
            good.append(g)
        full = 1 << n
        # brute: enumerate every row mask combination via recursion over rows.
        from functools import lru_cache

        def valid_self(mask, g):
            if mask & ~g:
                return False
            if mask & (mask << 1):
                return False
            return True

        def popcount(x):
            c = 0
            while x:
                c += x & 1
                x >>= 1
            return c

        best = [0]

        def rec(r, prev):
            if r == m:
                return 0
            res = 0
            for mask in range(full):
                if not valid_self(mask, good[r]):
                    continue
                if (mask & (prev << 1)) or (mask & (prev >> 1)):
                    continue
                res = max(res, popcount(mask) + rec(r + 1, mask))
            return res

        return rec(0, 0)

