class Solution:
    def maxStudents(self, seats):
        m = len(seats)
        n = len(seats[0])
        good = []
        for row in seats:
            g = 0
            for j, ch in enumerate(row):
                if ch == '.':
                    g |= 1 << j
            good.append(g)
        full = 1 << n
        valid_masks = []
        for r in range(m):
            masks = []
            for mask in range(full):
                if mask & ~good[r]:
                    continue
                if mask & (mask << 1):
                    continue
                masks.append(mask)
            valid_masks.append(masks)
        NEG = float('-inf')
        prev_dp = {0: 0}
        for r in range(m):
            cur = {}
            for mask in valid_masks[r]:
                pc = bin(mask).count('1')
                best = NEG
                for pmask, pval in prev_dp.items():
                    if mask & (pmask << 1):
                        continue
                    if mask & (pmask >> 1):
                        continue
                    if pval + pc > best:
                        best = pval + pc
                if best > NEG:
                    cur[mask] = best
            prev_dp = cur
        return max(prev_dp.values()) if prev_dp else 0

