var maxStudents = function(seats) {
    const m = seats.length, n = seats[0].length;
    const good = [];
    for (const row of seats) {
        let g = 0;
        for (let j = 0; j < n; j++) if (row[j] === '.') g |= 1 << j;
        good.push(g);
    }
    const full = 1 << n;
    const popcount = (x) => { let c = 0; while (x) { c += x & 1; x >>>= 1; } return c; };
    const validMasks = [];
    for (let r = 0; r < m; r++) {
        const masks = [];
        for (let mask = 0; mask < full; mask++) {
            if (mask & ~good[r] & (full - 1)) continue;
            if (mask & (mask << 1)) continue;
            masks.push(mask);
        }
        validMasks.push(masks);
    }
    let prev = new Map([[0, 0]]);
    for (let r = 0; r < m; r++) {
        const cur = new Map();
        for (const mask of validMasks[r]) {
            const pc = popcount(mask);
            let best = -Infinity;
            for (const [pmask, pval] of prev) {
                if (mask & (pmask << 1)) continue;
                if (mask & (pmask >> 1)) continue;
                if (pval + pc > best) best = pval + pc;
            }
            if (best > -Infinity) cur.set(mask, best);
        }
        prev = cur;
    }
    let ans = 0;
    for (const v of prev.values()) if (v > ans) ans = v;
    return ans;
};
